class Solution {
public:
    int orderOfLargestPlusSign(int n, vector<vector<int>>& mines) {
        vector<vector<int>> grid(n, vector<int>(n, 1));
        for (auto& mine : mines) {
            grid[mine[0]][mine[1]] = 0;
        }

        int maxOrder = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 1) {
                    int order = 1;
                    while (i - order >= 0 && i + order < n && j - order >= 0 && j + order < n) {
                        if (grid[i - order][j] == 1 && grid[i + order][j] == 1 && grid[i][j - order] == 1 && grid[i][j + order] == 1) {
                            order++;
                        } else {
                            break;
                        }
                    }
                    maxOrder = max(maxOrder, order);
                }
            }
        }
        return maxOrder;
    }
};
